class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            using var transaction = db.Database.BeginTransaction();
            db.Database.Migrate();
            transaction.Commit();
        });
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9: Migrate() now manages its own transactions and execution
    // strategy. Wrapping it in a user transaction throws at runtime.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

